def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    kwargs = {
        'hosts': [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        'max_retries': 3,
        'retry_on_timeout': True,
        'request_timeout': 10,
        'maxsize': 25,  # Connection pool size for high traffic
    }

    if ES_USERNAME and ES_PASSWORD:
        kwargs['basic_auth'] = (ES_USERNAME, ES_PASSWORD)

    return Elasticsearch(**kwargs)


es_client = get_es_client()


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       in_stock=None, sort_by=None, sort_order='desc'):
    """Build an Elasticsearch query with optional filters."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search with multi-match across relevant fields
    if keyword:
        must_clauses.append({
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',          # Boost product name matches
                    'name.autocomplete^2',
                    'description^1.5',
                    'brand^2',
                    'category^1',
                    'tags^1',
                    'sku^4',           # Exact SKU matches boosted highest
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%',
            }
        })

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = float(min_price)
        if max_price is not None:
            price_range['lte'] = float(max_price)
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # In-stock filter
    if in_stock is not None:
        filter_clauses.append({
            'term': {'in_stock': in_stock}
        })

    query = {
        'bool': {
            'must': must_clauses if must_clauses else [{'match_all': {}}],
            'filter': filter_clauses,
        }
    }

    # Build sort
    sort = []
    if sort_by:
        valid_sort_fields = ['price', 'created_at', 'rating', 'popularity']
        if sort_by in valid_sort_fields:
            sort.append({sort_by: {'order': sort_order}})
    
    # Always add _score as secondary sort for relevance
    if not sort_by or sort_by != '_score':
        sort.insert(0, '_score')

    return query, sort


def build_aggregations():
    """Build aggregations for faceted search."""
    return {
        'categories': {
            'terms': {
                'field': 'category.keyword',
                'size': 50,
            }
        },
        'brands': {
            'terms': {
                'field': 'brand.keyword',
                'size': 50,
            }
        },
        'price_ranges': {
            'range': {
                'field': 'price',
                'ranges': [
                    {'key': 'under_25', 'to': 25},
                    {'key': '25_to_50', 'from': 25, 'to': 50},
                    {'key': '50_to_100', 'from': 50, 'to': 100},
                    {'key': '100_to_200', 'from': 100, 'to': 200},
                    {'key': 'over_200', 'from': 200},
                ]
            }
        },
        'avg_price': {
            'avg': {
                'field': 'price'
            }
        },
        'in_stock_count': {
            'filter': {
                'term': {'in_stock': True}
            }
        }
    }


def format_product(hit):
    """Format an Elasticsearch hit into a product response."""
    source = hit.get('_source', {})
    return {
        'id': hit.get('_id'),
        'score': hit.get('_score'),
        'name': source.get('name'),
        'description': source.get('description'),
        'price': source.get('price'),
        'currency': source.get('currency', 'USD'),
        'brand': source.get('brand'),
        'category': source.get('category'),
        'image_url': source.get('image_url'),
        'thumbnail_url': source.get('thumbnail_url'),
        'rating': source.get('rating'),
        'review_count': source.get('review_count'),
        'in_stock': source.get('in_stock'),
        'sku': source.get('sku'),
        'tags': source.get('tags', []),
        'url': source.get('url'),
    }


def format_aggregations(aggs):
    """Format Elasticsearch aggregations into a clean response."""
    formatted = {}

    if 'categories' in aggs:
        formatted['categories'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['categories'].get('buckets', [])
        ]

    if 'brands' in aggs:
        formatted['brands'] = [
            {'name': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['brands'].get('buckets', [])
        ]

    if 'price_ranges' in aggs:
        formatted['price_ranges'] = [
            {'range': bucket['key'], 'count': bucket['doc_count']}
            for bucket in aggs['price_ranges'].get('buckets', [])
        ]

    if 'avg_price' in aggs:
        formatted['avg_price'] = aggs['avg_price'].get('value')

    if 'in_stock_count' in aggs:
        formatted['in_stock_count'] = aggs['in_stock_count'].get('doc_count', 0)

    return formatted


@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Search products endpoint.
    
    Query Parameters:
        q (str): Search keyword (required)
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter
        in_stock (bool): Filter by stock availability
        sort_by (str): Sort field (price, created_at, rating, popularity)
        sort_order (str): Sort order (asc, desc). Default: desc
        page (int): Page number (1-based). Default: 1
        page_size (int): Results per page. Default: 20, Max: 100
        facets (bool): Include aggregations/facets. Default: false
    
    Returns:
        JSON response with products, pagination info, and optional facets.
    """
    start_time = time.time()

    # Extract and validate query parameters
    keyword = request.args.get('q', '').strip()
    if not keyword:
        return jsonify({
            'error': 'Missing required parameter',
            'message': 'Query parameter "q" is required',
        }), 400

    if len(keyword) > 500:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'Query parameter "q" must be 500 characters or less',
        }), 400

    category = request.args.get('category', None)
    min_price = request.args.get('min_price', None)
    max_price = request.args.get('max_price', None)
    in_stock = request.args.get('in_stock', None)
    sort_by = request.args.get('sort_by', None)
    sort_order = request.args.get('sort_order', 'desc')
    include_facets = request.args.get('facets', 'false').lower() == 'true'

    # Validate numeric parameters
    try:
        if min_price is not None:
            min_price = float(min_price)
            if min_price < 0:
                raise ValueError("min_price must be non-negative")
        if max_price is not None:
            max_price = float(max_price)
            if max_price < 0:
                raise ValueError("max_price must be non-negative")
        if min_price is not None and max_price is not None and min_price > max_price:
            raise ValueError("min_price must be less than or equal to max_price")
    except ValueError as e:
        return jsonify({
            'error': 'Invalid parameter',
            'message': str(e),
        }), 400

    # Parse boolean in_stock
    if in_stock is not None:
        in_stock = in_stock.lower() in ('true', '1', 'yes')

    # Validate sort_order
    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    # Pagination
    try:
        page = max(1, int(request.args.get('page', 1)))
        page_size = min(MAX_PAGE_SIZE, max(1, int(request.args.get('page_size', DEFAULT_PAGE_SIZE))))
    except (ValueError, TypeError):
        page = 1
        page_size = DEFAULT_PAGE_SIZE

    offset = (page - 1) * page_size

    # Prevent deep pagination (ES default limit is 10000)
    if offset + page_size > 10000:
        return jsonify({
            'error': 'Pagination limit exceeded',
            'message': 'Cannot paginate beyond 10000 results. Use more specific search terms.',
        }), 400

    # Build the query
    query, sort = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
        in_stock=in_stock,
        sort_by=sort_by,
        sort_order=sort_order,
    )

    # Build the search body
    search_body = {
        'query': query,
        'sort': sort,
        'from': offset,
        'size': page_size,
        'timeout': SEARCH_TIMEOUT,
        '_source': [
            'name', 'description', 'price', 'currency', 'brand',
            'category', 'image_url', 'thumbnail_url', 'rating',
            'review_count', 'in_stock', 'sku', 'tags', 'url',
        ],
        'highlight': {
            'fields': {
                'name': {'number_of_fragments': 0},
                'description': {
                    'fragment_size': 150,
                    'number_of_fragments': 2,
                },
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>'],
        },
        'suggest': {
            'text': keyword,
            'keyword_suggestion': {
                'term': {
                    'field': 'name',
                    'suggest_mode': 'popular',
                    'min_word_length': 3,
                }
            }
        }
    }

    if include_facets:
        search_body['aggs'] = build_aggregations()

    try:
        response = es_client.search(
            index=ES_INDEX,
            body=search_body,
        )
    except Exception as e:
        logger.error(f"Elasticsearch search error: {str(e)}", exc_info=True)
        return jsonify({
            'error': 'Search service unavailable',
            'message': 'An error occurred while processing your search. Please try again.',
        }), 503

    # Parse response
    hits = response.get('hits', {})
    total_hits = hits.get('total', {}).get('value', 0)
    total_relation = hits.get('total', {}).get('relation', 'eq')
    timed_out = response.get('timed_out', False)
    took_ms = response.get('took', 0)

    # Format products
    products = []
    for hit in hits.get('hits', []):
        product = format_product(hit)

        # Add highlights if present
        highlight = hit.get('highlight', {})
        if highlight:
            product['highlights'] = {
                field: fragments
                for field, fragments in highlight.items()
            }

        products.append(product)

    # Format suggestions
    suggestions = []
    suggest_data = response.get('suggest', {}).get('keyword_suggestion', [])
    for entry in suggest_data:
        for option in entry.get('options', []):
            suggestions.append({
                'text': option.get('text'),
                'score': option.get('score'),
                'freq': option.get('freq'),
            })

    # Calculate pagination metadata
    total_pages = (total_hits + page_size - 1) // page_size if total_hits > 0 else 0

    # Build response
    result = {
        'query': keyword,
        'total': total_hits,
        'total_relation': total_relation,  # 'eq' for exact, 'gte' for lower bound
        'page': page,
        'page_size': page_size,
        'total_pages': total_pages,
        'has_next': page < total_pages,
        'has_prev': page > 1,
        'products': products,
        'suggestions': suggestions if suggestions else None,
        'timed_out': timed_out,
        'took_ms': took_ms,
    }

    # Add facets if requested
    if include_facets and 'aggregations' in response:
        result['facets'] = format_aggregations(response['aggregations'])

    elapsed_ms = round((time.time() - start_time) * 1000, 2)
    result['response_time_ms'] = elapsed_ms

    # Log search metrics for monitoring
    logger.info(
        f"Search query='{keyword}' results={total_hits} "
        f"page={page} es_took={took_ms}ms total_time={elapsed_ms}ms "
        f"timed_out={timed_out}"
    )

    response = jsonify(result)

    # Cache headers for high-traffic scenarios
    # Short cache for search results to balance freshness and performance
    response.headers['Cache-Control'] = 'public, max-age=30, stale-while-revalidate=60'
    response.headers['Vary'] = 'Accept-Encoding'

    return response, 200


@app.route('/api/search/suggest', methods=['GET'])
def search_suggest():
    """
    Autocomplete/suggestion endpoint for search-as-you-type.
    
    Query Parameters:
        q (str): Partial search term
        size (int): Number of suggestions. Default: 5, Max: 20
    """
    keyword = request.args.get('q', '').strip()
    if not keyword or len(keyword) < 2:
        return jsonify({'suggestions': []}), 200

    try:
        size = min(20, max(1, int(request.args.get('size', 5))))
    except (ValueError, TypeError):
        size = 5

    search_body = {
        'size': 0,
        'suggest': {
            'product_suggest': {
                'prefix': keyword,
                'completion': {
                    'field': 'name.suggest',
                    'size': size,
                    'skip_duplicates': True,
                    'fuzzy': {
                        'fuzziness': 'AUTO',
                        'prefix_length': 2,
                    }
                }
            }
        }
    }

    try:
        response = es_client.search(
            index=ES_INDEX,
            body=search_body,
        )
    except Exception as e:
        logger.error(f"Elasticsearch suggest error: {str(e)}", exc_info=True)
        return jsonify({'suggestions': []}), 200  # Graceful degradation

    suggestions = []
    suggest_data = response.get('suggest', {}).get('product_suggest', [])
    for entry in suggest_data:
        for option in entry.get('options', []):
            suggestions.append({
                'text': option.get('text'),
                'score': option.get('_score'),
                'id': option.get('_id'),
            })

    result = jsonify({'query': keyword, 'suggestions': suggestions})
    result.headers['Cache-Control'] = 'public, max-age=60, stale-while-revalidate=120'
    return result, 200


@app.route('/api/search/health', methods=['GET'])
def search_health():
    """Health check endpoint for the search service."""
    try:
        health = es_client.cluster.health(timeout='5s')
        es_status = health.get('status', 'unknown')

        # Check if the index exists
        index_exists = es_client.indices.exists(index=ES_INDEX)

        is_healthy = es_status in ('green', 'yellow') and index_exists

        return jsonify({
            'status': 'healthy' if is_healthy else 'degraded',
            'elasticsearch': {
                'cluster_status': es_status,
                'index_exists': index_exists,
                'cluster_name': health.get('cluster_name'),
                'number_of_nodes': health.get('number_of_nodes'),
            }
        }), 200 if is_healthy else 503

    except Exception as e:
        logger.error(f"Health check failed: {str(e)}")
        return jsonify({
            'status': 'unhealthy',
            'error': str(e),
        }), 503


